query:
-- Verificar quantos ativos não têm endereço
SELECT COUNT(*) as ativos_sem_endereco FROM establishments WHERE status = 'active' AND (address IS NULL OR address = '');

-- Marcar como Pendente os ativos sem endereço válido
UPDATE establishments SET status = 'pending' WHERE status = 'active' AND (address IS NULL OR address = '');

